import subprocess
import sys

def dump_partition(serial, partition):
    cmd = f'adb -s {serial} shell dd if=/dev/block/by-name/{partition} of=/sdcard/{partition}.img'
    result = subprocess.run(cmd, shell=True, capture_output=True, text=True)
    if result.returncode == 0:
        print(f'Successfully dumped {partition}')
    else:
        print(f'Error dumping {partition}: {result.stderr}')

if __name__ == '__main__':
    if len(sys.argv) != 3:
        print('Usage: python dump_partition.py <serial> <partition>')
        sys.exit(1)
    dump_partition(sys.argv[1], sys.argv[2])
